import adastra from"adastra-plugin";import fs from"fs/promises";import glob from"glob";import path from"path";import{defineConfig}from"vite";const PACKAGE_PREFIX="lifesync",delayFullReload=()=>({name:"delay-full-reload",handleHotUpdate:({server:server})=>(setTimeout((()=>{server.ws.send({type:"full-reload"})}),500),[])});export default()=>defineConfig({build:{emptyOutDir:!1,rollupOptions:{output:{assetFileNames:"lifesync-[name]-[hash][extname]",entryFileNames:"lifesync-[name]-[hash].js",chunkFileNames:"lifesync-chunk-[name]-[hash].js"}}},resolve:{alias:{"@":path.resolve(__dirname,"src")}},app:"mpa",plugins:[adastra(),cleanOldAssets(),delayFullReload()]});const cleanOldAssets=()=>({name:"clean-old-assets",closeBundle:async()=>{try{const data=JSON.parse(await fs.readFile("assets/adastra.manifest.json","utf-8")),allowed_files=Object.values(data).map((item=>item.file)),files=glob.sync("assets/**/lifesync-*.{css,js}");for(const file of files)allowed_files.includes(path.basename(file))||await fs.unlink(file,(()=>{console.log(`Deleted ${file}`)}));console.log("Cleaned up assets folder")}catch(error){console.error(`Error: ${error}`)}}});